import re

def scan_unsafe_code(code_str):
    dangerous_patterns = [
        r'__import__\(\s*["\']os["\']\s*\).*system',
        r'eval\(|exec\(',
        r'rm\s+-rf',
        r'open\([^,]+,\s*["\']w["\']\)'
    ]
    for pattern in dangerous_patterns:
        if re.search(pattern, code_str, re.IGNORECASE):
            return {'issue': 'UNSAFE_CODE', 'pattern': pattern}
    return None

from smolagents import Agent, tool

def validate_tool_call(tool_name, args):
    tool_schemas = {
        'calculator': {'args': {'a': float, 'b': float, 'op': str}},
        'search': {'args': {'query': str}}
    }
    schema = tool_schemas.get(tool_name)
    if not schema:
        return {'valid': False, 'error': 'Unknown tool'}

    for arg_name, arg_val in args.items():
        if arg_name not in schema['args']:
            return {'valid': False, 'error': f'Invalid arg: {arg_name}'}
    return {'valid': True}

import ast
class ReasoningTracker:
    def __init__(self):
        self.variables = {}

    def track_step(self, code_str):
        tree = ast.parse(code_str)
        errors = []
        for node in ast.walk(tree):
            if isinstance(node, ast.Assign):
                for target in node.targets:
                    if isinstance(target, ast.Name):
                        self.variables[target.id] = 'updated'
            elif isinstance(node, ast.BinOp) and isinstance(node.op, ast.Div):
                if any(var.id in self.variables for var in ast.walk(node.left) if isinstance(var, ast.Name)):
                    errors.append('Potential division by tracked zero-risk variable')
        return errors

