from pydantic import BaseModel, validator

class CalcInput(BaseModel):
    a: float
    b: float
    op: str

    @validator('op')
    def valid_op(cls, v):
        if v not in ['+', '-', '*', '/']:
            raise ValueError('Invalid operation')
        return v

@tool
async def calculator(input: CalcInput) -> float:
