    # ... other ops
    return 0.0

from smolagents import Agent

def resilient_agent_run(agent, task):
    max_retries = 3
    for attempt in range(max_retries):
        try:
            result = agent.run(task)
            return result
        except ZeroDivisionError:
            agent.memory['error'] = 'Division by zero detected'
            task += " Avoid division by zero. Previous error: " + str(agent.memory.get('error'))
        except Exception as e:
            agent.memory['last_error'] = str(e)
    raise Exception('Max retries exceeded')
